INSERT INTO sleep_guidelines (id, evidence_level, recommendation, citation_id, citation_title, citation_authors, citation_journal, citation_year, citation_doi, target_athlete_type, target_age_group, target_position, sleep_phase, implementation_steps, expected_benefits, contraindications, created_at) VALUES (1, 'very_high', 'Athletes should aim for 7-9 hours of sleep per night for optimal performance and recovery', NULL, 'Sleep and Athletic Performance: Impacts on Physical Performance, Mental Performance, Injury Risk and Recovery in Athletes', '["Watson AM"]', 'Sleep Medicine Clinics', 2017, NULL, 'all', NULL, NULL, 'sleep_quality', '["Establish consistent sleep schedule","Create dark, quiet sleep environment","Avoid screens 1 hour before bed"]', '["improved reaction time","better decision making","enhanced recovery","reduced injury risk"]', NULL, '2025-08-17T20:28:03.178Z');
